import React from 'react'
import { Link } from 'react-router-dom'

import './CheckoutSteps.css'


function CheckoutSteps({ step1, step2, step3, step4 }) {
  return (
    <div className='checkout-nav-body'>
      
      {step1 ? <Link to='/login'>Login    ></Link>
          : <Link disabled>Login</Link>}

      {step2 ? <Link to='/shipping'>Shipping</Link>
          : <Link disabled>Shipping</Link>}

      {step3 ? <Link to='/payment'>Payment</Link>
          : <Link disabled>Payment</Link>}

      {step4 ? <Link to='/placeorder'>Place Order</Link>
          : <Link disabled>Place Order</Link>}

    </div>
  )
}

export default CheckoutSteps
